import React from 'react';

function Trade(props) {
    return(
        <div>
            {props.trade.id}
            {props.trade.stock}
            {props.trade.method}
            {props.trade.quantity}
            {props.trade.profitLoss}
        </div>
    )
}

export default Trade;
